/**
 * BrutxUI Prism Theme — Neo-Brutalist Syntax Highlighting
 *
 * 使用专用 --brutal-code-* 变量控制 token 颜色，
 * 与 --brutal-primary 等设计令牌解耦，确保所有主题下对比度达标。
 * 消费者可通过覆盖 --brutal-code-* 变量自定义高亮配色。
 */

code[class*="language-"],
pre[class*="language-"] {
    color: var(--brutal-code-foreground, var(--brutal-fg));
    font-family: ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, "Liberation Mono", monospace;
    line-height: 1.7;
    white-space: pre;
    word-spacing: normal;
    word-break: normal;
    word-wrap: normal;
    tab-size: 4;
    hyphens: none;
}

/* --- Token 颜色映射 --- */
/* 所有颜色均通过 --brutal-code-* 变量，默认值确保 WCAG AA 对比度 >= 4.5:1 */

.token.comment,
.token.prolog,
.token.doctype,
.token.cdata {
    color: var(--brutal-code-comment, #6b7280);
    font-style: italic;
}

.token.punctuation {
    color: var(--brutal-code-punctuation, #4b5563);
}

.token.property,
.token.tag,
.token.boolean,
.token.number,
.token.constant,
.token.symbol,
.token.deleted {
    color: var(--brutal-code-number, #c0392b);
}

.token.selector,
.token.attr-name,
.token.string,
.token.char,
.token.builtin,
.token.inserted {
    color: var(--brutal-code-string, #2e7d32);
}

.token.operator,
.token.entity,
.token.url {
    color: var(--brutal-code-operator, #1565c0);
}

.token.atrule,
.token.attr-value,
.token.keyword {
    color: var(--brutal-code-keyword, #00838f);
}

.token.function,
.token.class-name {
    color: var(--brutal-code-function, #c62828);
}

.token.regex,
.token.important,
.token.variable {
    color: var(--brutal-code-variable, #9c27b0);
}

/* --- 暗色模式覆盖 --- */

.dark {
    --brutal-code-comment: #9ca3af;
    --brutal-code-punctuation: #d1d5db;
    --brutal-code-number: #ef5350;
    --brutal-code-string: #66bb6a;
    --brutal-code-operator: #42a5f5;
    --brutal-code-keyword: #26c6da;
    --brutal-code-function: #ff7043;
    --brutal-code-variable: #ce93d8;
}

/* --- 行号样式（Prism 插件兼容） --- */

.line-numbers .line-numbers-rows {
    border-right: var(--brutal-border-width, 3px) solid var(--brutal-border-color);
    padding-right: 1rem;
    margin-right: 1rem;
}

.line-numbers-rows > span::before {
    color: var(--brutal-fg);
    opacity: 0.3;
}

/* --- 高亮行（Prism line-highlight 插件兼容） --- */

.line-highlight {
    background: var(--brutal-accent);
    opacity: 0.15;
}

import { cva } from 'class-variance-authority'
import { brutalPressWithTransition } from '@/lib/brutal-interaction-variants'

export const codeBlockRootVariants = cva(
    'border-3 border-brutal bg-brutal-bg text-brutal-fg rounded-brutal shadow-brutal overflow-hidden'
)

export const codeBlockHeaderVariants = cva(
    'bg-brutal-muted border-b-3 border-brutal flex justify-between items-center px-4 py-2 text-xs font-black select-none'
)

export const codeBlockLanguageVariants = cva(
    'bg-brutal-accent text-brutal-fg border-3 border-brutal rounded-brutal px-1.5 py-0.5 text-[10px] uppercase font-black tracking-wider'
)

export const codeBlockBodyVariants = cva(
    'relative flex items-stretch p-4 overflow-x-auto text-sm font-mono bg-brutal-bg'
)

export const codeBlockLineNumbersVariants = cva(
    'flex flex-col text-right text-brutal-fg/40 select-none pr-4 mr-4 border-r-3 border-brutal font-bold'
)

export const codeBlockCopyButtonVariants = cva(
    `h-7 px-3 text-xs border-3 border-brutal shadow-brutal-sm ${brutalPressWithTransition} bg-brutal-bg hover:bg-brutal-muted`
)

import { type ComputedRef, type InjectionKey, type MaybeRef, computed, inject, provide, unref } from 'vue'
import { zhCN } from '@/locales/zh-CN'
import type { Locale } from '@/locales/types'

export const LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Locale>> = Symbol('brutx-ui-locale')
export const FALLBACK_LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Partial<Locale>>> = Symbol('brutx-ui-fallback-locale')

export type TranslateFunction = (path: string, params?: Record<string, string | number>) => string

export interface LocaleOptions {
    locale: MaybeRef<Locale>
    fallbackLocale?: MaybeRef<Partial<Locale>>
}

export function provideLocale(localeOrOptions: MaybeRef<Locale> | LocaleOptions): void {
    // 检查是否是 LocaleOptions 格式（包含 locale 属性）
    if (
        typeof localeOrOptions === 'object' &&
        localeOrOptions !== null &&
        'locale' in localeOrOptions
    ) {
        const options = localeOrOptions as LocaleOptions
        provide(LOCALE_INJECTION_KEY, options.locale)
        if (options.fallbackLocale) {
            provide(FALLBACK_LOCALE_INJECTION_KEY, options.fallbackLocale)
        }
    } else {
        // 直接传入 MaybeRef<Locale> 格式（向后兼容）
        provide(LOCALE_INJECTION_KEY, localeOrOptions as MaybeRef<Locale>)
    }
}

function resolveByPath(obj: unknown, path: string): string | undefined {
    const keys = path.split('.')
    let result: unknown = obj
    for (const key of keys) {
        if (typeof result !== 'object' || result === null) return undefined
        result = (result as Record<string, unknown>)[key]
    }
    return typeof result === 'string' ? result : undefined
}

function interpolate(template: string, params?: Record<string, string | number>): string {
    if (!params) return template
    return Object.entries(params).reduce(
        (str, [k, v]) => str.split(`{${k}}`).join(String(v)),
        template,
    )
}

export function useLocale(): { locale: ComputedRef<Locale>; t: TranslateFunction } {
    const injected = inject<MaybeRef<Locale> | undefined>(LOCALE_INJECTION_KEY, undefined)
    const injectedFallback = inject<MaybeRef<Partial<Locale>> | undefined>(FALLBACK_LOCALE_INJECTION_KEY, undefined)

    const locale = computed<Locale>(() => {
        const resolved = injected ? unref(injected) : undefined
        return resolved ?? zhCN
    })

    const fallbackLocale = computed<Partial<Locale>>(() => {
        return injectedFallback ? unref(injectedFallback) : {}
    })

    function t(path: string, params?: Record<string, string | number>): string {
        // 1. 尝试从用户 locale 查找
        const currentVal = resolveByPath(locale.value, path)
        if (currentVal !== undefined) return interpolate(currentVal, params)

        // 2. 尝试从自定义 fallback locale 查找
        if (fallbackLocale.value && Object.keys(fallbackLocale.value).length > 0) {
            const fallbackVal = resolveByPath(fallbackLocale.value, path)
            if (fallbackVal !== undefined) return interpolate(fallbackVal, params)
        }

        // 3. 尝试从默认 zhCN 查找
        const zhCNVal = resolveByPath(zhCN, path)
        if (zhCNVal !== undefined) return interpolate(zhCNVal, params)

        // 4. 返回 path 原文
        return path
    }

    return { locale, t }
}
